import { NextResponse } from 'next/server';
import * as fs from 'fs';
import * as path from 'path';

function loadEnv(): Record<string, string> {
    const envPath = path.resolve(process.cwd(), '../.env');
    try {
        if (fs.existsSync(envPath)) {
            const content = fs.readFileSync(envPath, 'utf-8');
            const vars: Record<string, string> = {};
            content.split('\n').forEach(line => {
                const trimmed = line.trim();
                if (!trimmed || trimmed.startsWith('#')) return;
                const eqIdx = trimmed.indexOf('=');
                if (eqIdx === -1) return;
                const key = trimmed.substring(0, eqIdx).trim();
                let val = trimmed.substring(eqIdx + 1).trim();
                if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
                    val = val.slice(1, -1);
                }
                vars[key] = val;
            });
            return vars;
        }
    } catch (e) { console.error("Env read error:", e); }
    return {};
}

export async function POST(req: Request) {
    try {
        const env = loadEnv();
        const body = await req.json();
        const { messages } = body;

        // DEFINICIÓN DE PROVEEDORES ÚNICAMENTE EN LA NUBE (NADA DE LOCAL/OLLAMA)
        const providers = [
            // 🚀 GOOGLE GEMINI NATIVA (8 FALLBACKS DE NUBE)
            ...[1, 2, 3, 4, 5, 6, 7, 8].map(i => ({
                id: `Gemini-Cloud-${i}`,
                key: env[`GEMINI_KEY_${i}`],
                url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${env[`GEMINI_KEY_${i}`]}`,
                model: "gemini-2.0-flash",
                type: "gemini_native"
            })),

            // 🚀 CEREBRAS (NUBE)
            {
                id: "Cerebras-Cloud",
                key: env.CEREBRAS_API_KEY,
                url: "https://api.cerebras.ai/v1/chat/completions",
                model: "llama3.3-70b",
                type: "openai"
            }
        ];

        let log = "";
        let validWaysFound = 0;

        for (const p of providers) {
            if (!p.key || p.key.includes("SUTITUYE") || p.key === "") continue;

            validWaysFound++;
            try {
                console.log(`[OpenGravity] Intentando con ${p.id} (Nube)...`);

                let response;
                if (p.type === 'gemini_native') {
                    response = await fetch(p.url, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            contents: messages.map((m: any) => ({
                                role: m.role === 'assistant' ? 'model' : 'user',
                                parts: [{ text: m.content }]
                            }))
                        })
                    });
                } else {
                    response = await fetch(p.url, {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                            'Authorization': `Bearer ${p.key}`
                        },
                        body: JSON.stringify({
                            model: p.model,
                            messages: messages.map((m: any) => ({ role: m.role, content: m.content })),
                            max_tokens: 1024
                        })
                    });
                }

                if (!response.ok) {
                    const errText = await response.text();
                    throw new Error(`HTTP ${response.status}: ${errText.substring(0, 50)}...`);
                }

                const data = await response.json();
                let reply = "";

                if (p.type === 'gemini_native') reply = data.candidates?.[0]?.content?.parts?.[0]?.text;
                else reply = data.choices?.[0]?.message?.content;

                if (reply) {
                    console.log(`[OpenGravity] ✅ ${p.id} OK (NUBE)`);
                    return NextResponse.json({ reply: `*[Engine: ${p.id}]*\n\n${reply}` });
                }
            } catch (e: any) {
                log += `[❌ ${p.id}]: ${e.message}\n`;
                console.warn(`[OpenGravity] Falló ${p.id}`);
            }
        }

        if (validWaysFound === 0) {
            return NextResponse.json({ reply: "⚠️ No hay motores de NUBE configurados. Revisa el archivo .env." });
        }

        return NextResponse.json({ reply: `❌ Fallo total en la nube. Reporte:\n${log}` });

    } catch (error: any) {
        return NextResponse.json({ reply: "Error crítico en el router de OpenGravity." }, { status: 500 });
    }
}
